package com.infy.inventrack.catalog.controller; import com.infy.inventrack.catalog.service.CategoryService; import com.infy.inventrack.common.dto.*; import jakarta.validation.Valid; import org.springframework.http.*; import org.springframework.web.bind.annotation.*; @RestController @RequestMapping("/categories") public class CategoryController { private final CategoryService service; public CategoryController(CategoryService s){service=s;} @PostMapping public ResponseEntity<String> create(@Valid @RequestBody CategoryRequest r){return ResponseEntity.status(HttpStatus.CREATED).body(service.createCategory(r));} @PutMapping("/{id}") public ResponseEntity<CategoryResponse> update(@PathVariable Integer id,@Valid @RequestBody CategoryRequest r){return ResponseEntity.ok(service.updateCategory(id,r));} @DeleteMapping("/{id}") public ResponseEntity<String> delete(@PathVariable Integer id){return ResponseEntity.ok(service.deleteCategory(id));} }
